353	  func setupStatusItem() {
354	    let item = NSStatusBar.system.statusItem(withLength: NSStatusItem.variableLength)
355	    if let button = item.button {
356	      button.font = NSFont.systemFont(ofSize: NSFont.systemFontSize, weight: .semibold)
357	      button.toolTip = NSLocalizedString("Squirrel", comment: "")
358	    }
359	    statusItem = item
