364	  func updateStatusItemVisibility() {
365	    guard let statusItem = statusItem else { return }
366	    let currentInputSourceID = SquirrelInstaller.currentInputSourceID() ?? ""
367	    statusItem.isVisible = currentInputSourceID.hasPrefix("im.rime.inputmethod.Squirrel")
368	  }
369	
370	  // macOS 26 does not call deactivateServer when the input source is switched
371	  // away by another process via TISSelectInputSource() (e.g. macism, Input
372	  // Source Pro): the pending composition is stranded and the candidate panel
373	  // is left orphaned on screen (#1140). The input-source-changed notification
374	  // is still delivered, so finalize the composition here as a fallback.
375	  // Switching via the menu bar calls deactivateServer first, making this a
376	  // no-op.
377	  func finalizeStrandedComposition() {
378	    let currentInputSourceID = SquirrelInstaller.currentInputSourceID() ?? ""
379	    guard !currentInputSourceID.hasPrefix("im.rime.inputmethod.Squirrel") else { return }
380	    if let inputController = panel?.inputController {
381	      inputController.deactivateServer(inputController.client())
382	    }
383	  }
