385	  func applyStatusIcon(asciiMode: Bool, schemaLabel: String?) {
386	    guard let button = statusItem?.button else { return }
387	    if let schemaLabel = schemaLabel, !schemaLabel.isEmpty {
388	      button.title = schemaLabel
389	    } else {
390	      button.title = asciiMode ? "Ａ" : "中"
391	    }
392	  }
