414	  func rimeToggleASCIIMode(_ notification: Notification) {
415	    guard let mode = notification.object as? String else { return }
416	    let enableASCII = mode == "ascii"
417	
418	    if enableASCII {
419	      NotificationCenter.default.post(name: .init("SquirrelSetASCIIModeNotification"), object: true)
420	    } else {
421	      NotificationCenter.default.post(name: .init("SquirrelSetASCIIModeNotification"), object: false)
422	    }
423	  }
424	
425	  func rimeGetASCIIMode(_: Notification) {
426	    NotificationCenter.default.post(name: .init("SquirrelReportASCIIModeNotification"), object: nil)
427	  }
