429	  func createDirIfNotExist(path: URL) {
430	    let fileManager = FileManager.default
431	    if !fileManager.fileExists(atPath: path.path()) {
432	      do {
433	        try fileManager.createDirectory(at: path, withIntermediateDirectories: true)
434	      } catch {
435	        print("Error creating user data directory: \(path.path())")
436	      }
437	    }
438	  }
439	}
